const sample = {
  schema: 'botfucker.approved_actions.v1',
  safety_scope: 'provider_action_export_only',
  actions: [
    {
      audit_id: 'audit-outlook-draft-sample-0001',
      item_id: 'review-item-sample-0001',
      provider: 'microsoft_outlook',
      approved_action: 'approve_warning',
      provider_execution: 'not_performed',
      message_id: 'AAMkAGI2FAKE_MESSAGE_ID',
      warning_body: 'This is a fake, human-approved warning draft body for sandbox rehearsal only.'
    }
  ]
};
return [{ json: sample }];

const emergencyStopRaw = String($env.BOTFUCKER_EMERGENCY_STOP || 'true').toLowerCase();
const emergencyStop = !['0', 'false', 'off', 'no'].includes(emergencyStopRaw);
if (emergencyStop) {
  return [{ json: { scaffold_status: 'blocked_by_emergency_stop', provider_execution: 'not_performed' } }];
}
const bundle = $input.first().json || {};
if (bundle.schema !== 'botfucker.approved_actions.v1') {
  throw new Error('Unexpected approved action schema');
}
if (bundle.safety_scope !== 'provider_action_export_only') {
  throw new Error('Unexpected safety scope');
}
const processedRaw = $env.BOTFUCKER_PROCESSED_AUDIT_IDS || '';
const processedAuditIds = new Set(processedRaw.split(',').map((value) => value.trim()).filter(Boolean));
const actions = Array.isArray(bundle.actions) ? bundle.actions : [];
return actions.filter((action) => {
  const provider = String(action.provider || '').toLowerCase();
  return action.audit_id
    && !processedAuditIds.has(action.audit_id)
    && action.provider_execution === 'not_performed'
    && action.approved_action === 'approve_warning'
    && ['outlook', 'microsoft_outlook'].includes(provider)
    && action.message_id
    && action.warning_body;
}).map((action) => ({
  json: {
    ...action,
    provider: 'microsoft_outlook',
    draft_only: true,
    graph_operation: 'createReply',
    scaffold_status: 'validated_for_disabled_draft_step'
  }
}));

return $input.all().map((item) => {
  const input = item.json || {};
  if (input.scaffold_status === 'blocked_by_emergency_stop') {
    return {
      json: {
        ...input,
        provider_execution: 'not_performed',
        draft_only: false,
        graph_operation: 'none',
        note: 'Emergency stop is on; scaffold is blocked before any draft readiness signal.'
      }
    };
  }
  return {
    json: {
      audit_id: input.audit_id,
      item_id: input.item_id,
      provider: 'microsoft_outlook',
      approved_action: 'approve_warning',
      provider_execution: 'not_performed',
      draft_only: true,
      graph_operation: 'createReply',
      scaffold_status: 'ready_for_manual_sandbox_rehearsal',
      note: 'The Graph draft node is disabled and unconnected in this export.'
    }
  };
});
